import React, { useState, useContext } from 'react';
import { View, TextInput, Button, StyleSheet } from 'react-native';
import { AppContext } from '../context/AppContext';

export default function CreateGroupScreen({ navigation }) {
  const [title, setTitle] = useState('');
  const { createGroup } = useContext(AppContext);

  const handleCreate = () => {
    if (!title.trim()) return;
    const g = createGroup(title.trim());
    navigation.replace('Chat', { groupId: g.id });
  };

  return (
    <View style={styles.container}>
      <TextInput placeholder="ชื่อกลุ่ม" value={title} onChangeText={setTitle} style={styles.input} />
      <Button title="สร้างกลุ่ม (Invite-only)" onPress={handleCreate} />
    </View>
  );
}

const styles = StyleSheet.create({ container: { flex: 1, padding: 16 }, input: { borderWidth: 1, borderColor: '#ccc', padding: 10, borderRadius: 6, marginBottom: 12 } });
